import{_ as e,c as i,a,o as n}from"./app-CEcM0piI.js";const l={};function t(d,s){return n(),i("div",null,s[0]||(s[0]=[a(`<p>Cascading Style Sheets，层叠样式表 是一种用来为结构化文档（如 HTML 文档或 XML 应用）添加样式（字体、间距和颜色等）的计算机语言</p><p>css对样式的设定需要写在<code>&lt;style&gt;&lt;/style&gt;</code>标签中,style标签通常写在html的<code>&lt;head&gt;&lt;/head&gt;</code>标签中</p><p>对选择器更改的样式会一直作用在本文件中 其语法为:<code>选择器{样式}</code>,如:</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;style&gt;</span></span>
<span class="line"><span>    p {</span></span>
<span class="line"><span>        color: red;</span></span>
<span class="line"><span>        font-size: 12px;</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>&lt;/style&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>这样在此页面中使用的<code>&lt;p&gt;&lt;/p&gt;</code>标签中的内容都变为红色,字体大小都为12像素了</p><h2 id="字体设置" tabindex="-1"><a class="header-anchor" href="#字体设置"><span>字体设置</span></a></h2><p><strong>字体</strong> 属性front-family可以设置字体</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>p{</span></span>
<span class="line"><span>	front-family:Arial,&#39;Microsoft YaHei&#39;,&#39;微软雅黑&#39;;</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>可以设置多个字体,不同字体间使用逗号隔开,字体名称不是英文的或者是有多个英文单词拼成的需要用引号引用,多个英文单词之间还需要用空格隔开 设置多个字体浏览器会按先后顺序,如果前一个字体客户电脑上没有安装会往后查看,直到有电脑上安装的字体才会用该字体显示</p><p><strong>大小</strong><code>front-size</code>设置文字大小 通常单位是像素</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>front-size:16px;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p><strong>粗细</strong><code>front-weight</code>设置文字粗细</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>front-weight:300;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>可以使用数字尺寸,可以使用默认给出的选项</p><p><strong>字体样式</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>front-style:normal;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>通常只有两种normal是浏览器默认样式,italic是斜体</p><h4 id="复合属性" tabindex="-1"><a class="header-anchor" href="#复合属性"><span>复合属性</span></a></h4><p>复合属性可以简写代码</p><p>如字体复合属性顺序:</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>front:font-style font-weight font-size/line-height font-family;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>复合属性值的顺序是不可改变的</p><p>用法:</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>front:italic 700 16px/10px &#39;Microsoft yahei&#39;;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>字体复合属性如果有些属性用不到可以省略,但大小和字体不能省略</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>front:16px &#39;Microsoft yahei&#39;;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p><strong>行高</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>font:12px/1.5</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>设置字体为12像素乘行高的1.5倍</p><h2 id="文本属性" tabindex="-1"><a class="header-anchor" href="#文本属性"><span>文本属性</span></a></h2><p><strong>颜色</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>color:#ffffff;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>可以使用颜色名blue,十六进制#ffffff,rgb值(255,255,255)</p><p><strong>对齐</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>text-align:center;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>left,right,center</p><p><strong>装饰文本</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>text-decoration:underline;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>none 默认,没有装饰线(最常用) underline 下划线。链接a自带下划线 (常用) overline 上划线。(几乎不用) line-through 删除线。(不常用)</p><p><strong>文本缩进</strong> text-indent属性用来指定文本的第一行的缩进，通常是将段落的首行缩进</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>text-indent:10px;</span></span>
<span class="line"><span>text-indent:2em;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>em是一个相对单位，就是当前元素（font-size)1个文字的大小,如果当前元素没有设置大小，则会按照父元素的1个文字大小。</p><p><strong>行间距</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>line-height:10px;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h2 id="css引入方式" tabindex="-1"><a class="header-anchor" href="#css引入方式"><span>CSS引入方式</span></a></h2><h3 id="内部样式表" tabindex="-1"><a class="header-anchor" href="#内部样式表"><span>内部样式表</span></a></h3><p>内部样式表（内嵌样式表）是写到html页面内部.是将所有的CSS代码抽取出来，单独放到一个&lt;style&gt;标签中。</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;style&gt;</span></span>
<span class="line"><span>	div{</span></span>
<span class="line"><span>		color:red;</span></span>
<span class="line"><span>		font-size:12px;</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>&lt;/style&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>&lt;style&gt;标签理论上可以放在HTML文档的任何地方，但一般会放在文档的&lt;head&gt;标签中</li><li>通过此种方式，可以方便控制当前整个页面中的元素样式设置</li><li>代码结构清晰，但是并没有实现结构与样式完全分离</li><li>使用内部样式表设定CSS，通常也被称为嵌入式引I入，这种方式是我们练习时常用的方式</li></ul><h3 id="行内样式表" tabindex="-1"><a class="header-anchor" href="#行内样式表"><span>行内样式表</span></a></h3><p>行内样式表（内联样式表）是在元素标签内部的style属性中设定CSS样式。适合于修改简单样式</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;divstyle=&quot;color：red；font-size：12px;&quot;&gt;2024/9/10 16:11&lt;/div&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ul><li>style其实就是标签的属性</li><li>在双引号中间，写法要符合CSS规范</li><li>可以控制当前的标签设置样式</li><li>由于书写繁琐，并且没有体现出结构与样式相分离的思想，所以不推荐大量使用，只有对当前元素添加简单样式的时候，可以考虑使用</li><li>使用行内样式表设定CSS，通常也被称为行内式引I入</li></ul><h3 id="外部样式表" tabindex="-1"><a class="header-anchor" href="#外部样式表"><span>外部样式表</span></a></h3><p>实际开发都是外部样式表.适合于样式比较多的情况.核心是：样式单独写到CSS文件中，之后把CSS文件引入到HTML页面中使用 引入外部样式表分为两步：</p><ol><li>新建一个后缀名为.css的样式文件，把所有css代码都放入此文件中。</li><li>在HTML页面的&lt;head&gt;标签中，使用&lt;link&gt;标签引入这个文件。</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt; link rel=&quot;stylesheet&quot; href=&quot;css文件路径&quot;&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>rel 定义当前文档与被链接文档之间的关系，在这里需要指定为&quot;stylesheet&quot;，表示被链接的文档是个样式表文件。 href 定义所链接外部样式表文件的URL，可以是相对路径，也可以是绝对路径。 使用外部样式表设定CSS，通常也被称为外链式或链接式引入，这种方式是开发中常用的方式</p><p>在.css文件中不需要写&lt;style&gt;标签,因为这是html的语法,在.css文件中只需要写css语法就行了</p><h1 id="emmet语法" tabindex="-1"><a class="header-anchor" href="#emmet语法"><span>Emmet语法</span></a></h1><p>Emmet语法的前身是Zencoding,它使用缩写，来提高html/css的编写速度，Vscode内部已经集成该语法</p><ol><li>快速生成HTML结构语法</li><li>快速生成CSS样式语法</li></ol><h3 id="快速生成html结构语法" tabindex="-1"><a class="header-anchor" href="#快速生成html结构语法"><span>快速生成HTML结构语法</span></a></h3><ol><li>生成标签直接输入标签名按tab键即可比如div然后tab键，就可以生成&lt;div&gt;&lt;/div&gt;</li><li>如果想要生成多个相同标签加上＊就可以了比如div*3就可以快速生成3个div</li><li>如果有父子级关系的标签，可以用〉比如ul&gt;l就可以了</li><li>如果有兄弟关系的标签，用+就可以了比如 div+p</li><li>如果生成带有类名或者id名字的，直接写.demo或者#two tab 键就可以了</li><li>如果生成的div类名是有顺序的，可以用自增符号$</li></ol><h3 id="快速生成css样式语法" tabindex="-1"><a class="header-anchor" href="#快速生成css样式语法"><span>快速生成CSS样式语法</span></a></h3><p>CSS基本采取简写形式即可.</p><ol><li>比如w200按tab 可以生成width:200px;</li><li>比如Ih26按tab 可以生成 line-height:26px;</li></ol><h1 id="元素显示模式的转换" tabindex="-1"><a class="header-anchor" href="#元素显示模式的转换"><span>元素显示模式的转换</span></a></h1><p>CSS中分为三类显示模式:</p><ol><li>块元素显示模式(独占一行,触发范围是一整块)</li><li>行显示模式(大部分都是文字,触发范围也只是文字范围)</li><li>行内块显示模式(不独占一行的块)</li></ol><p>如果想要在一个块或行内块的范围内触发与其中字体一样的触发效果就需要进行显示模式转换(即使行元素具有块元素的触发范围)增加字体点击范围(如果直接设置字体标签的大小也会改变文字的大小)</p><p>需要改变标签选择器中的属性 如:将a的触发范围改为块,将div触发范围改为行</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>a {</span></span>
<span class="line"><span>    display: block;</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>div {</span></span>
<span class="line"><span>    display: inline;</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h1 id="三大特性" tabindex="-1"><a class="header-anchor" href="#三大特性"><span>三大特性</span></a></h1><h2 id="层叠性" tabindex="-1"><a class="header-anchor" href="#层叠性"><span>层叠性</span></a></h2><p>相同选择器给设置相同的样式，此时一个样式就会覆盖（层叠）另一个冲突的样式。层叠性主要解决样式冲突</p><p>样式冲突，遵循的原则是就近原则，哪个样式离结构近，就执行哪个 样式样式不冲突，不会层叠</p><h2 id="继承性" tabindex="-1"><a class="header-anchor" href="#继承性"><span>继承性</span></a></h2><p>CSS中的继承：子标签会继承父标签的某些样式，如文本颜色和字号 和字体相关的都可继承包括行高 子元素可以继承父元素的样式（text-，font-，line-这些元素开头的可以继承，以及color属性）</p><h2 id="优先级" tabindex="-1"><a class="header-anchor" href="#优先级"><span>优先级</span></a></h2><p>当同一个元素指定多个选择器，就会有优先级的产生</p><ul><li>选择器相同，则执行层叠性</li><li>选择器不同，则根据选择器权重执行</li></ul><table><thead><tr><th>选择器</th><th>权重</th></tr></thead><tbody><tr><td>继承或者*</td><td>0,0,0,0</td></tr><tr><td>元素选择器</td><td>0,0,0,1</td></tr><tr><td>类选择器，伪类选择器</td><td>0,0,1,0</td></tr><tr><td>ID选择器</td><td>0,1,0,0</td></tr><tr><td>行内样式style=&quot;&quot;</td><td>1,0,0,0</td></tr><tr><td>!important重要的</td><td>无穷大</td></tr><tr><td>在属性后面加<code>!import</code>就可以提高权重</td><td></td></tr></tbody></table><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>div{</span></span>
<span class="line"><span>	color:pink!important;</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h1 id="css初始化" tabindex="-1"><a class="header-anchor" href="#css初始化"><span>CSS初始化</span></a></h1><p>不同浏览器对有些标签的默认值是不同的，为了消除不同浏览器对HTML文本呈现的差异，照顾浏览器的兼容，我们需要对CSS初始化 简单理解：CSS初始化是指重设浏览器的样式。(也称为CSSreset） 每个网页都必须首先进行CSS初始化。</p><p>Unicode编码字体： 把中文字体的名称用相应的Unicode编码来代替，这样就可以有效的避免浏览器解释CSS代码时候出现乱码的问题。</p><p>比如： 黑体\\9ED1\\4F53 宋体\\5B8B\\4F53 微软雅黑\\5FAE\\8F6F\\96C5\\9ED1</p>`,88)]))}const h=e(l,[["render",t]]),p=JSON.parse('{"path":"/front/css/1/","title":"1 基础","lang":"zh-CN","frontmatter":{"title":"1 基础","createTime":"2025/06/18 21:05:36","permalink":"/front/css/1/"},"readingTime":{"minutes":7.32,"words":2196},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/前端/CSS/1 基础.md","headers":[]}');export{h as comp,p as data};
